set -euo pipefail

sudo journalctl -u ssh --since "${1:-24 hours ago}" --no-pager |
 awk '/Failed password/ {
 for (i=1; i<=NF; i++) if ($i=="for") print $(i+1)
 }' |
 sort | uniq -c | sort -nr | head -n 20
```
This summarizes usernames seen in recent failed SSH password attempts.

```bash
#!/usr/bin/env bash
set -Eeuo pipefail
src=${1:?source path required}
dst=${2:?destination path required}

[[ -d "$src" ]] || { echo "source is not a directory: $src" >&2; exit 66; }
mkdir -p "$dst"
rsync -aHAX --numeric-ids --dry-run --delete --itemize-changes "$src"/ "$dst"/ | tee /tmp/rsync-preview.txt
printf 'preview_lines=%s
' "$(wc -l < /tmp/rsync-preview.txt)"
```
`--dry-run` previews destructive delete behaviour. `-aHAX` preserves common Linux metadata for system backups.

```bash
#!/usr/bin/env bash
set -Eeuo pipefail

ss -H -ltnp | awk '
{
 split($4, a, ":"); port=a[length(a)]
 proc=$0
 gsub(/.*users:\(\(/, "", proc); gsub(/,.*/, "", proc); gsub(/"/, "", proc)
 printf "{"port":%s,"process":"%s","raw":"%s"}
", port, proc, $0
}'
```
`ss -H` removes headers. The JSON is intentionally simple; for strict JSON escaping use Python or jq if available.

```bash
#!/usr/bin/env bash
set -Eeuo pipefail
unit=${1:?unit required}
minutes=${2:-30}

systemctl show "$unit" -p ActiveState -p SubState -p Result -p ExecMainStatus --no-pager
sudo journalctl -u "$unit" --since "$minutes minutes ago" --no-pager -p info..alert
```
This is better than dumping huge logs. It gives state fields and a bounded journal window.

```bash
#!/usr/bin/env bash
set -Eeuo pipefail
ca=${1:?path to .crt file required}

[[ -f "$ca" ]] || { echo "CA file missing: $ca" >&2; exit 66; }
[[ "$ca" == *.crt ]] || { echo "CA file should use .crt extension" >&2; exit 65; }
sudo install -m 0644 "$ca" /usr/local/share/ca-certificates/
sudo update-ca-certificates
```
Debian/Ubuntu trust update expects `.crt` files. Installing with a known mode avoids umask surprises.
